class TestLeftPaddedDecode(unittest.TestCase):
    """Item 16.15: left-padded batched decoding returns generated tokens only."""

    def test_only_generated_tokens_returned(self):
        # Fake model whose generate() appends known new tokens to input_ids.
        new_tokens = torch.tensor([[101, 102, 103], [201, 202, 203]])

        class FakeGenModel:
            def generate(self, input_ids, attention_mask, **kw):
                seqs = torch.cat([input_ids, new_tokens], dim=-1)
                return types.SimpleNamespace(
                    sequences=seqs, past_key_values=None
                )

        wrapper = ModelWrapper.__new__(ModelWrapper)
        wrapper.model = FakeGenModel()
        wrapper.tokenizer = FakeTokenizer()
        wrapper.device = torch.device("cpu")

        # Left-padded batch: row 0 has a leading pad (0); row 1 is full.
        input_ids = torch.tensor([[0, 5, 6], [7, 8, 9]])
        attention_mask = torch.tensor([[0, 1, 1], [1, 1, 1]])

        texts, _ = wrapper.generate_text_batch(
            input_ids,
            attention_mask,
            max_new_tokens=3,
        )

        # Decoded text must contain ONLY the generated tokens, not the prompt.
        self.assertEqual(texts[0], "101 102 103")
        self.assertEqual(texts[1], "201 202 203")


